--  DDL for View ACCOUNT_SUMMARY
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "SFMS"."ACCOUNT_SUMMARY" ("ACCOUNT_ID", "BALANCE") AS 
  SELECT account_id, balance
FROM ACCOUNTS
;
--------------------------------------------------------
--  DDL for View MEMBER_PAYMENTS
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "SFMS"."MEMBER_PAYMENTS" ("NAME", "AMOUNT", "PAYMENT_DATE") AS 
  SELECT m.name, p.amount, p.payment_date
FROM MEMBER m
JOIN PAYMENTS p ON m.member_id = p.member_id
;
--------------------------------------------------------
--  DDL for View PENDING_DUES
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "SFMS"."PENDING_DUES" ("NAME", "AMOUNT", "STATUS") AS 
  SELECT m.name, d.amount, d.status
FROM MEMBER m
JOIN DUES d ON m.member_id = d.member_id
WHERE LOWER(d.status) = 'pending'
;
