--------------------------------------------------------
--  DDL for Trigger TRG_UPDATE_BALANCE
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SFMS"."TRG_UPDATE_BALANCE" 
AFTER INSERT ON TRANSACTIONS
FOR EACH ROW
BEGIN
    IF LOWER(:NEW.type) = 'payment' THEN
        UPDATE ACCOUNTS
        SET balance = balance + :NEW.amount
        WHERE account_id = :NEW.account_id;

    ELSIF LOWER(:NEW.type) = 'expense' THEN
        UPDATE ACCOUNTS
        SET balance = balance - :NEW.amount
        WHERE account_id = :NEW.account_id;
    END IF;
END;

/
ALTER TRIGGER "SFMS"."TRG_UPDATE_BALANCE" ENABLE;
